// Função para converter volume em número (litros)
function volumeParaNumero(volume) {
  const v = (volume || '').toLowerCase().replace(/\s+/g, '').replace(',', '.');

  // Remove 'l' ou 'ml' e converte para número em litros
  let num = parseFloat(v.replace(/[a-z]/g, ''));

  if (v.includes('ml')) {
    num = num / 1000; // converte ml para litros
  }

  return isNaN(num) ? 0 : num;
}

// Função para mapear volume numérico para embalagem
function numeroParaEmbalagem(volumeLitros) {
  // Define os volumes padrão e suas embalagens
  const padroes = [
    { volume: 0.9, embalagem: 'LITRO' },
    { volume: 3.6, embalagem: 'GALÃO' },
    { volume: 18, embalagem: 'LATA' },
    { volume: 16, embalagem: 'LATA' }
  ];

  // Encontra o volume mais próximo
  let maisProximo = padroes[0];
  let menorDiferenca = Math.abs(volumeLitros - padroes[0].volume);

  for (const padrao of padroes) {
    const diferenca = Math.abs(volumeLitros - padrao.volume);
    if (diferenca < menorDiferenca) {
      menorDiferenca = diferenca;
      maisProximo = padrao;
    }
  }

  return maisProximo.embalagem;
}

// Pega o volume e acabamento que o cliente pediu
const volumePedido = items[0].json.volume;
const acabamentoEsperado = (items[0].json.acabamento || '').toLowerCase().trim();

// Converte o volume pedido para número e encontra a embalagem mais próxima
const volumeNumerico = volumeParaNumero(volumePedido);
const embalagemEsperada = numeroParaEmbalagem(volumeNumerico);

// Filtra a lista de produtos
const resultado = items.filter(item => {
  // A embalagem do item da API deve ser igual à embalagem mais próxima
  const matchEmbalagem = item.json.embalagemSimplificada === embalagemEsperada;

  // A lógica de acabamento continua a mesma
  const matchAcabamento = acabamentoEsperado
    ? (item.json.acabamento || '').toLowerCase().includes(acabamentoEsperado)
    : true;

  return matchEmbalagem && matchAcabamento;
});

// Se, após os filtros, a lista ficar vazia, retorna um erro.
if (resultado.length === 0) {
  throw new Error(`Nenhum produto encontrado para esse acabamento/embalagem. Volume pedido: ${volumePedido} (${volumeNumerico}L) → Embalagem sugerida: ${embalagemEsperada}`);
}

// Prepara os dados limpos para o próximo nó do fluxo
const dadosCliente = resultado.map(item => ({
  json: {
    codigoEmpresa: item.json.codigoEmpresa,
    sigla: item.json.sigla,
    cor: item.json.cor,
    volume: item.json.volume,
    rgb: item.json.rgb,
    codigoCor: item.json.codigoCor,
    acabamento: item.json.acabamento,
    embalagem: item.json.embalagemSimplificada,
    ordemEmbalagem: item.json.ordemEmbalagemSimplificada,
  }
}));

return dadosCliente;

// === 1) Referência e normalização ===
const ref = items[0]?.json || {};
const acabamentoCliente = ref.acabamento || '';

function normaliza(txt) {
  return (txt || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

// Equivalências (bidirecional simples)
const equivalencias = {
  // acetinado / sedoso
  acetinado: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  acetinada: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  seda:      ['acetinado', 'acetinada', 'seda', 'sedoso'],
  sedoso:    ['acetinado', 'acetinada', 'seda', 'sedoso'],

  // fosco
  fosco: ['fosco', 'matte'],
  matte: ['fosco', 'matte'],

  // brilhante
  brilhante: ['brilho', 'brilhante'],
  brilho:    ['brilho', 'brilhante'],
  semibrilho: ['diamante'],

  // clássica
  classica:    ['classica', 'tradicional'],
  tradicional: ['classica', 'tradicional'],
};

const acbClienteNorm = normaliza(acabamentoCliente);
const palavrasAceitas = acbClienteNorm
  ? (equivalencias[acbClienteNorm] || [acbClienteNorm])
  : null; // null => não filtra por acabamento quando cliente não informou

// === 2) Filtra itens válidos (descarta item 0 e quem não tem chaveCitel) ===
let candidatos = items.slice(1).filter(i => !!i?.json?.chaveCitel);

// === 3) Aplica filtro por acabamento (somente se cliente informou algo) ===
if (palavrasAceitas) {
  candidatos = candidatos.filter(i => {
    const acbItem = normaliza(i.json.acabamento);
    if (!acbItem) return false;
    return palavrasAceitas.some(word =>
      acbItem.includes(word) || word.includes(acbItem)
    );
  });
}

// === 4) Deduplica por chaveCitel (evita POST duplicado) ===
const vistos = new Set();
candidatos = candidatos.filter(i => {
  const k = String(i.json.chaveCitel);
  if (vistos.has(k)) return false;
  vistos.add(k);
  return true;
});

// === 5) Monta saída padronizada (hashesMd5 sempre preenchido) ===
return candidatos.map(i => ({
  json: {
    codigoCliente: "000001",
    codigoEmpresa: ref.codigoEmpresa,
    sigla: ref.sigla,
    idPro: ref.sigla,
    rgb: i.json.rgb,
    hashesMd5: [String(i.json.chaveCitel)],
    cor: i.json.cor,
    acabamento: i.json.acabamento,
    embalagem: i.json.embalagem,
    codigoCor: i.json.codigoCor ?? '',
  }
}));

// saída: [{ json: { mensagem } }]

// === UTILS (funções auxiliares) ===
const up = s => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toUpperCase().trim();

function volumeByEmbalagem(e = '') {
  const v = up(e);
  if (v.includes('LATA')) return '18 L';
  if (v.includes('GALAO')) return '3,6 L';
  if (v.includes('LITRO') || v === 'L') return '0,9 L';
  return '';
}

function embalagemEsperada(volume) {
  const v = String(volume || '').replace(',', '.').replace(/\s+/g,'').toUpperCase();
  if (v.startsWith('18'))  return 'LATA';
  if (v.startsWith('3.6')) return 'GALAO';
  if (v.startsWith('0.9') || v.startsWith('0.5') || v.includes('900ML')) return 'LITRO';
  return '';
}
// === FIM UTILS ===


// 1) Pega os metadados do pedido do cliente (o último item)
const meta = items[items.length - 1]?.json || {};
const SIGLA  = up(meta.sigla);
const SUPERF = up(meta.superficie || meta['superfície']);
const ACABPD = up(meta.acabamento || meta.acabamentoPedido);
const VOLRAW = meta.volume || '';
const CODCOR = meta.codigoCor || '';

// 2) Define a sub-categoria (se é premium fosco, acetinado, etc.)
function catKey(acabPed) {
  if (acabPed.includes('FOSCO') && acabPed.includes('LAV')) return 'premium_fosco_lavavel';
  if (acabPed.includes('FOSCO')) return 'premium_fosco';
  if (acabPed.includes('ACET')) return 'premium_acetinado';
  if (acabPed.includes('SEMI') || acabPed.includes('BRILHO')) return 'premium_semibrilho';
  return 'premium_fosco';
}
const CAT = catKey(ACABPD);

// 3) Separa descrições e preços, depois combina por hash
const descs  = items.filter(i => Array.isArray(i.json?.hashesMd5)).map(i => i.json);
const prices = items.filter(i => typeof i.json?.hashMd5 === 'string').map(i => i.json);
const priceByHash = Object.fromEntries(prices.map(p => [p.hashMd5, p]));

let produtos = descs.map(d => {
  const h = d.hashesMd5?.[0];
  const p = priceByHash[h];
  if (!p) return null;
  return {
    sigla: d.sigla,
    cor: d.cor,
    acabamento: d.acabamento,
    embalagem: d.embalagem,
    volume: d.volume,
    preco: Number(p.preco1 || 0),
    estoque: Number(p.estoqueDisponivel || 0),
    hash: h,
  };
}).filter(Boolean);

// 4) Filtra por embalagem coerente com o volume
const embOK = embalagemEsperada(VOLRAW);
if (embOK) produtos = produtos.filter(p => up(p.embalagem) === embOK);

// ✅ REGRA 1: Sempre prioriza TMC INSPIRA se existir nos candidatos com preço > 0
const tmcInspira = produtos.find(p => {
  const acab = up(p.acabamento);
  return acab.includes('TMC INSPIRA') && p.preco > 0;
});

if (tmcInspira) {
  const volStr = volumeByEmbalagem(tmcInspira.embalagem) || tmcInspira.volume || VOLRAW || '';
  const desc = `${tmcInspira.sigla} ${tmcInspira.cor} ${tmcInspira.acabamento} ${tmcInspira.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
  const precoBRL = tmcInspira.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const disponibilidade = tmcInspira.estoque > 0 ? '✅ Disponível em estoque' : '⚠️ Sob consulta';
  const mensagem = `• ${desc}\n💰 Preço: ${precoBRL}\n📦 ${disponibilidade}\n\nPosso seguir com esse item?`;

  return [{ json: { mensagem } }];
}

// 5) REGRAS DE PRIORIDADE POR MARCA E CATEGORIA
const regras = {
  premium_fosco: {
    SUV: ['TOQUE FOSCO COMPLETO'], 
    SHW: ['METALATEX ACRILICO FOSCO', 'NOVO METALATEX ACRILICO FOSCO'],
    CIM: ['DECORA MATTE FO', '3 EM 1 FOSCO', 'CORAL MASTER FOSCO'],
    TMC: ['INSPIRA FOSCO', 'TMC INSPIRA FOSCO'],
  },
  premium_fosco_lavavel: {
    SUV: ['SEMPRE LIMPO'],
    CIM: ['SUPER LAVAVEL'],
  },
  premium_acetinado: {
    SUV: ['TOQUE DE SEDA', 'TOQUE SEDA'],
    SHW: ['METALATEX ELASTIC SEMIACETINADO'],
    CIM: ['DECORA SEDA'],
  },
  premium_semibrilho: {
    SUV: ['TOQUE BRILHO'],
    SHW: ['METALATEX ACRILICO SEMIBRILHO'],
    CIM: ['DECORA DIAMANTE'],
  },
};

// 6) Função que busca produtos seguindo as regras de prioridade
function pickByPriority(sigla, cat, listaProdutos) {
  const arr = (regras[cat] || {})[sigla] || [];
  if (!arr.length) return null;

  for (const alvo of arr) {
    const A = up(alvo);
    const found = listaProdutos.find(p => {
        const acabamentoProduto = up(p.acabamento);
        return acabamentoProduto.includes(A) && p.preco > 0;
    });

    if (found) return found;
  }
  return null;
}

// 7) Tenta encontrar produto seguindo as regras de prioridade
const escolhidoPrioridade = pickByPriority(SIGLA, CAT, produtos);

if (escolhidoPrioridade) {
  const volStr = volumeByEmbalagem(escolhidoPrioridade.embalagem) || escolhidoPrioridade.volume || VOLRAW || '';
  const desc = `${escolhidoPrioridade.sigla} ${escolhidoPrioridade.cor} ${escolhidoPrioridade.acabamento} ${escolhidoPrioridade.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
  const precoBRL = escolhidoPrioridade.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const disponibilidade = escolhidoPrioridade.estoque > 0 ? '✅ Disponível em estoque' : '⚠️ Sob consulta';
  const mensagem = `• ${desc}\n💰 Preço: ${precoBRL}\n📦 ${disponibilidade}\n\nPosso seguir com esse item?`;

  return [{ json: { mensagem } }];
}

// 8) ⚡ FALLBACK: Se não encontrou pelas regras, pega o mais próximo com MENOR PREÇO
// Remove produtos com preço zero
produtos = produtos.filter(p => p.preco > 0);

if (produtos.length === 0) {
  return [{ json: { mensagem: `Não encontrei produtos disponíveis com preço para o volume ${VOLRAW}. Verifique a disponibilidade com nosso atendimento.` } }];
}

// Sistema de pontuação para o fallback (considera acabamento + preço)
function scoreAcabamentoFallback(acabamento) {
  const acab = up(acabamento);

  // Prioriza produtos que tenham o tipo de acabamento pedido
  if (ACABPD.includes('ACET') && acab.includes('ACET')) return 500;
  if (ACABPD.includes('FOSCO') && acab.includes('FOSCO')) return 500;
  if (ACABPD.includes('BRILHO') && acab.includes('BRILHO')) return 500;
  if (ACABPD.includes('SEMI') && acab.includes('SEMI')) return 500;

  // Prioridade para linhas conhecidas
  if (acab.includes('BIOPROTECT')) return 300;
  if (acab.includes('ELASTIC')) return 280;
  if (acab.includes('ESMALTE SINTETICO')) return 250;
  if (acab.includes('ESMALTE ECO') || acab.includes('ECO')) return 220;
  if (acab.includes('TMC ESM')) return 200;

  return 100;
}

// Ordena por: compatibilidade de acabamento (desc), estoque (desc), preço (asc)
produtos.sort((a, b) => {
  const scoreA = scoreAcabamentoFallback(a.acabamento);
  const scoreB = scoreAcabamentoFallback(b.acabamento);

  if (scoreB !== scoreA) return scoreB - scoreA; // maior score primeiro
  if (b.estoque !== a.estoque) return b.estoque - a.estoque; // com estoque primeiro
  return a.preco - b.preco; // menor preço primeiro
});

const escolhidoFallback = produtos[0];

const volStr = volumeByEmbalagem(escolhidoFallback.embalagem) || escolhidoFallback.volume || VOLRAW || '';
const desc = `${escolhidoFallback.sigla} ${escolhidoFallback.cor} ${escolhidoFallback.acabamento} ${escolhidoFallback.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
const precoBRL = escolhidoFallback.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const disponibilidade = escolhidoFallback.estoque > 0 ? '✅ Disponível em estoque' : '⚠️ Sob consulta';

const mensagem = `• ${desc}\n💰 Preço: ${precoBRL}\n📦 ${disponibilidade}\n\n⚠️ Produto sugerido baseado em disponibilidade e melhor preço.`;

return [{ json: { mensagem } }];

// Delay aleatório para dessincronizar
const delay = Math.random() * 2000;
await new Promise(resolve => setTimeout(resolve, delay));
return items;

// 🔥 CORREÇÃO: Pega dados do trigger original, não do Redis
const payload = $('Início: Receber Pedido do Cliente').first().json;

// 🔗 mapeamento fixo de marcas
const marcas = [
  { codigoEmpresa: '179', sigla: 'CIM', nome: 'CORAL' },
  { codigoEmpresa: '179', sigla: 'SHW', nome: 'SHERWIN WILLIAMS' },
  { codigoEmpresa: '179', sigla: 'SUV', nome: 'SUVINIL' },
];

// 📌 aliases de marcas (apelidos → nome oficial)
const aliases = {
  'tmc': 'sherwin williams',
  'tintas mc': 'sherwin williams',
  'sw': 'sherwin williams',
  'sherwin': 'sherwin williams',
  'sherwin-williams':'sherwin williams',
  'cim': 'coral',
  'suv': 'suvinil',
};

// 🔄 trata entrada de marca ou sigla
let marcaEntrada = (payload.Marca || '').toLowerCase().trim();
if (aliases[marcaEntrada]) {
  marcaEntrada = aliases[marcaEntrada];
}
const marca = marcas.find(m =>
  m.nome.toLowerCase() === marcaEntrada || m.sigla.toLowerCase() === marcaEntrada
);
if (!marca) throw new Error(`Marca '${payload.Marca}' não mapeada`);

// ==========================================================
// Normalização da cor → remove acentos, artigos e cores genéricas
// ==========================================================
const normalizaCor = cor => {
  const stop = [
    'o ', 'a ', 'os ', 'as ', 'um ', 'uma ', 'de ', 'do ', 'da ', 'dos ', 'das ',
    'cinza ', 'branco ', 'preto ', 'amarelo ', 'azul ', 'verde ', 'vermelho ',
    'rosa ', 'marrom ', 'bege ', 'violeta ', 'roxo '
  ];
  let s = String(cor ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/\p{Diacritic}/gu, '')
    .trim();
  const w = stop.find(p => s.startsWith(p));
  if (w) s = s.slice(w.length).trim();
  return s;
};

// ==========================================================
// Aliases de categoria → premium | standard | economica
// ==========================================================
const norm = s => String(s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/\p{Diacritic}/gu, '')
  .trim();

const categoriaAliases = {
  premium: [
    'premium', 'super premium', 'prime', 'top', 'topo', 'linha premium',
    'superior', 'gold', 'platina', 'platinum', 'diamante'
  ],
  standard: [
    'standard', 'standart', 'intermediaria', 'intermediario', 'intermediário',
    'intermediária', 'medio', 'médio', 'media', 'média', 'padrao', 'padrão',
    'tradicional', 'regular', 'comum', 'linha media', 'linha média'
  ],
  economica: [
    'economica', 'economico', 'econômica', 'econômico', 'economy',
    'entrada', 'basica', 'básica', 'popular', 'barata', 'mais barata',
    'essencial', 'value', 'promo', 'oferta', 'iniciante', 'starter'
  ],
};

function mapCategoria(catBruta) {
  const c = norm(catBruta);

  if (!c) return 'standard'; // default seguro

  // checa por prioridade: premium → standard → economica
  for (const alvo of categoriaAliases.premium)   if (c.includes(alvo))   return 'premium';
  for (const alvo of categoriaAliases.standard)  if (c.includes(alvo))   return 'standard';
  for (const alvo of categoriaAliases.economica) if (c.includes(alvo))   return 'economica';

  // heurísticas simples
  if (/(prem|top|superior)/.test(c)) return 'premium';
  if (/(inter|medio|m[eé]dio|padr[aã]o|trad)/.test(c)) return 'standard';
  if (/(econ|barat|b[aá]sic|popular|value|promo|oferta)/.test(c)) return 'economica';

  return 'standard';
}

// ==========================================================
// Função para converter KG para Litros (L)
// ==========================================================
const converteVolumeKgParaL = (volumeInput) => {
  if (!volumeInput) return '';

  const v = String(volumeInput).toLowerCase().replace(/\s+/g, '').replace(',', '.');

  if (v.includes('kg')) {
    if (v.startsWith('25') || v.startsWith('28')) {
      return '18L';
    }
    if (v.startsWith('3.6') || v.startsWith('5') || v.startsWith('5.6')) {
      return '3.6L';
    }
    if (v.startsWith('1.2') || v.startsWith('1.4') || v.startsWith('1.5')) {
      return '0.9L';
    }
  }

  return payload.Volume;
};

// Chama a nova função para tratar o volume
const volumeProcessado = converteVolumeKgParaL(payload.Volume);

// Normaliza categoria com aliases
const categoriaProcessada = mapCategoria(payload.categoria);

// ==========================================================
// Saída final para próximo HTTP
// ==========================================================
return [
  {
    json: {
      codigoEmpresa: marca.codigoEmpresa,
      sigla: marca.sigla,
      cor: normalizaCor(payload.Cor),
      volume: volumeProcessado,
      acabamento: payload.Acabamento,
      superficie: payload['superfície'] ?? payload.superficie ?? '',
      telefoneCliente: payload.telefoneCliente,
      categoria: categoriaProcessada,
    },
  },
];
